                    text = block.get('text', '')
                    if len(text) > 50:
                        print(f'[{role}] {text[:300]}')
                        print('---')
        elif isinstance(content, str) and len(content) > 50:
            print(f'[{role}] {content[:300]}')
            print('---')
    except:
        pass
